import React, { useState, useRef } from "react";
import axios from "axios";
import { useCodeMirror } from "@uiw/react-codemirror";
import { python } from "@codemirror/lang-python";
import { oneDark } from "@codemirror/theme-one-dark";

function PythonCompiler() {
  const [pythonCode, setPythonCode] = useState("");
  const [input, setInput] = useState("");
  const [output, setOutput] = useState("");
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [inputRequired, setInputRequired] = useState(false);
  const [inputType, setInputType] = useState("");
  const [logOutput, setLogOutput] = useState("");
  const [messages, setMessages] = useState([
    {
      text: "Hii, I am ChatAI...! How can I help you?",
      isBot: true,
    },
  ]);
  const [clicked, setClicked] = useState(false);

  const pythonEditor = useRef(null);

  useCodeMirror({
    container: pythonEditor.current,
    value: pythonCode,
    theme: oneDark,
    extensions: [python(), oneDark],
    onChange: (value) => {
      setPythonCode(value);
      setLogOutput(`PYTHON: ${value}`);
    },
  });

  const doesCodeRequireInput = (code) => {
    return code.includes("input(");
  };

  const compilePythonCode = async () => {
    setError("");
    setOutput("");

    if (doesCodeRequireInput(pythonCode) && input.trim() === "") {
      setInputType("string");
      setError("Please provide input for the code — expected string.");
      setInputRequired(true);
      return;
    }

    setLoading(true);
    setInputRequired(false);

    const postData = {
      language: "python",
      version: "3.10.0",
      files: [
        {
          name: "main.py",
          content: pythonCode,
        },
      ],
      stdin: input,
    };

    try {
      const res = await axios.post(
        "https://emkc.org/api/v2/piston/execute",
        postData,
        {
          headers: {
            "Content-Type": "application/json",
          },
        }
      );

      setOutput(cleanOutput(res.data.run.output || "No output from the server."));
    } catch (error) {
      console.error("Error:", error.response ? error.response.data : error.message);
      setError("Failed to compile Python code. Please check your code and try again.");
    }

    setLoading(false);
  };

  const cleanOutput = (output) => {
    return output.replace(/`/g, "").replace(/\*/g, "").trim();
  };

  const clearInput = () => {
    setInput("");
    setError("");
    setInputRequired(false);
  };

  const generateAns = async () => {
    setLoading(true);
    setError("");

    try {
      const res = await axios.post(
        "https://generativelanguage.googleapis.com/v1beta/models/gemini-1.5-flash-latest:generateContent?key=AIzaSyCok-7EJjFVuirqtP0Rzzpi5u-im4zvuYA",
        {
          contents: [{ parts: [{ text: logOutput }] }],
        },
        {
          headers: {
            "Content-Type": "application/json",
          },
        }
      );

      const botResponse = cleanOutput(
        res.data?.candidates?.[0]?.content?.parts?.[0]?.text || "No response received"
      );
      setMessages((prevMessages) => [
        { text: botResponse, isBot: true },
        ...prevMessages,
      ]);
    } catch (error) {
      console.error("Error:", error.response ? error.response.data : error.message);
      setMessages((prevMessages) => [
        { text: "Failed to generate AI response.", isBot: true },
        ...prevMessages,
      ]);
      setError("Failed to generate AI response. Please try again.");
    }
    setLoading(false);
  };

  const handleClick = () => {
    setClicked(true);
    setTimeout(() => {
      setClicked(false);
    }, 2000);
  };

  return (
    <div className="PythonCompiler">
      <h1 className="comH1">Python Compiler</h1>
      <div className="editor-container">
        <div className="ele1">
          <br />
          <div className="row">
            <h3 className="compWri">Write Your Python Code:</h3>
            <button
              onClick={compilePythonCode}
              className="submit"
              style={{ border: "none" }}
            >
              <b>{loading ? "Compiling..." : "Compile and Run"}</b>
            </button>
          </div>
          <br />
          <div ref={pythonEditor} className="editor" />
        </div>

        <div className="ele2">
          <div className="iptDiv">
            <h3 style={{ color: "white", textAlign: "left", marginLeft: "15px" }}>
              <b>Input: </b>
            </h3>
            <textarea
              value={input}
              onChange={(e) => setInput(e.target.value)}
              placeholder="Enter input here (if your code requires input)....!"
              className="input-textarea"
            />
            <br />
            <button onClick={clearInput} className="clear-input-btn">
              Clear Input
            </button>
          </div>

          <div className="optDiv">
            {error && <div className="error">{error}</div>}
            {inputRequired && (
              <div className="input-message" style={{ color: "orange" }}>
                Please provide input for the code — expected {inputType}.
              </div>
            )}
            <h3 style={{ color: "white", marginTop: "0px", textAlign: "left", marginLeft: "15px" }}>
              Output:
            </h3>

            <textarea
              className="output"
              value={output}
              style={{
                marginTop: "0px",
                paddingLeft: "15px",
                border: "none",
                outline: "none",
                padding: "10px",
                resize: "none",
              }}
              disabled
            />
          </div>
        </div>
      </div>

      <h1 className="comH1" style={{ color: "rgb(223, 240, 254)" }}>
        Code with AI{" "}
      </h1>

      <div className="aiPage">
        <div className="ele2" style={{ borderRight: "5px solid #16181b" }}>
          <button
            className={`colorChangeBtn ${clicked ? "clicked" : ""}`}
            onClick={() => {
              handleClick();
              generateAns();
            }}
          >
            <b>{loading ? "Generating AI Response..." : "Generate AI Response"}</b>
          </button>
          <br />
        </div>

        <div className="ele1" style={{ border: "none" }}>
          <div className="user pad hight">
            <textarea
              value={logOutput}
              className="textArea hight input"
              style={{
                width: "90%",
                marginLeft: "5%",
                height: "300px",
                outline: "none",
                resize: "none",
              }}
              disabled
            />
          </div>
          <br />
          {error && <div style={{ color: "red" }}>{error}</div>}

          {messages.map((message, i) => (
            <textarea
              key={i}
              className={`pad hight textArea ${message.isBot ? "aiAns" : "userAns"}`}
              style={
                message.text.includes("Hii, I am ChatAI...! How can I help you?")
                  ? {
                      textAlign: "center",
                      fontFamily: "serif",
                      color: "green",
                      height: "40px",
                      paddingTop: "25px",
                      fontSize: "1.5rem",
                      borderRadius: "30px",
                      resize: "none",
                      backgroundColor: "black",
                    }
                  : {}
              }
              value={message.text}
              disabled
            />
          ))}
          <br />
          <br />
        </div>
      </div>
      <br />
      <br />
    </div>
  );
}

export default PythonCompiler;
